    const yearStart = new Date(fiscalYear, 0, 1);
    const yearEnd = new Date(fiscalYear, 11, 31);

    const completedPMs = await this.db.query.pmSchedule.findMany({
      where: and(
        eq(pmSchedule.status, 'COMPLETED'),
        gte(pmSchedule.completedAt, yearStart),
        lte(pmSchedule.completedAt, yearEnd),
        depotId ? eq(pmSchedule.assignedDepotId, depotId) : undefined
      )
    });

    let actualLaborCost = 0;
    let actualMaterialCost = 0;

    for (const pm of completedPMs) {
      const cost = await this.calculatePMCost(pm.id);
      actualLaborCost += cost.laborCost + cost.overtimeCost;
      actualMaterialCost += cost.materialCost;
    }

    const actualTotal = actualLaborCost + actualMaterialCost;
    const budgetTotal = baseline.budgetTotal;

    return {
